mapper.sql:
from aiw_investment_theme_snapshot s
where 1 = 1

    and s.task_code = #{criteria.taskCode}


    and s.snapshot_type = #{criteria.snapshotType}


    and s.theme_code = #{criteria.themeCode}


    and s.snapshot_time >= #{criteria.snapshotFrom}


    and s.snapshot_time <= #{criteria.snapshotTo}

mapper.select:
select s.* 
order by ${sortColumn}

    asc
    desc

limit #{offset}, #{criteria.size}
